<template><div class="login-page"><div class="login-box"><h2>能耗监测子系统</h2><el-form :model="f" size="large"><el-form-item><el-input v-model="f.useraccount" placeholder="账号" prefix-icon="User"/></el-form-item><el-form-item><el-input v-model="f.userpassword" type="password" placeholder="密码" prefix-icon="Lock" show-password @keyup.enter="doLogin"/></el-form-item><el-form-item><el-button type="primary" :loading="loading" style="width:100%" @click="doLogin">登 录</el-button></el-form-item></el-form></div></div></template>
<script setup lang="ts">
import { reactive, ref } from 'vue'; import { useRouter } from 'vue-router'; import { useAuthStore, useAppStore } from '@/stores/index'; import { login, getMyBuilding, getTitle } from '@/api/index'; import { ElMessage } from 'element-plus'
const router = useRouter(); const auth = useAuthStore(); const app = useAppStore()
const loading = ref(false); const f = reactive({ useraccount: 'admin', userpassword: '' })
async function doLogin() { loading.value = true; try { const r: any = await login(f); if (r.success) { auth.setToken(r.token); auth.setUser(r.user); const b: any = await getMyBuilding(); if (b.success && b.building) app.setBuilding(b.building.sign, b.building.name); router.push('/home'); ElMessage.success('登录成功') } else ElMessage.error(r.message) } catch { ElMessage.error('登录失败') } finally { loading.value = false } }
</script>
<style scoped>.login-page{height:100vh;display:flex;align-items:center;justify-content:center;background:linear-gradient(135deg,#0f2027,#203a43,#2c5364)}.login-box{width:380px;background:#fff;border-radius:8px;padding:40px 36px 30px;box-shadow:0 8px 40px rgba(0,0,0,.3)}.login-box h2{text-align:center;margin-bottom:28px;color:#1a1a2e;font-size:22px}</style>
